import type { CareerQuestion } from "./rrt-questions";

  export const imagingQuestionsBatch3: CareerQuestion[] = [
    {id:"img-b3-001",stem:"What is the purpose of the backup timer on an AEC system?",options:["To extend exposure time","To improve image contrast","To terminate the exposure if the AEC fails to do so, preventing excessive patient dose","To calibrate the AEC sensors"],correctIndex:2,rationale:"The backup timer is a safety mechanism that sets a maximum exposure time (typically 150% of expected manual technique). If the AEC malfunctions or the wrong detector is selected, the backup timer prevents overexposure.",difficulty:5,category:"Equipment Operation",topic:"AEC safety"},
    {id:"img-b3-002",stem:"During a barium swallow study, aspiration is demonstrated when:",options:["Barium enters the trachea and bronchi below the level of the vocal cords","Barium refluxes into the esophagus","Barium coats the gastric mucosa","Barium passes through a stricture"],correctIndex:0,rationale:"Aspiration is defined as passage of material below the true vocal cords into the trachea and bronchial tree. This is a serious finding that may lead to aspiration pneumonia. Penetration is material entering the larynx but not passing the cords.",difficulty:5,category:"Procedures",topic:"swallowing studies"},
    {id:"img-b3-003",stem:"The purpose of using an air gap technique instead of a grid is to:",options:["Reduce scatter reaching the image receptor by allowing scatter to diverge away from the receptor due to increased OID","Increase scatter radiation","Increase patient dose","Reduce magnification"],correctIndex:0,rationale:"An air gap (increased OID of 10-15 cm) allows scatter radiation (which diverges at wider angles) to miss the image receptor. It can replace a grid for lateral cervical spine and chest imaging but increases magnification.",difficulty:5,category:"Image Production",topic:"scatter reduction"},
    {id:"img-b3-004",stem:"What is the effect of increasing mAs on a digital radiograph?",options:["Lightens the image significantly","Decreases quantum noise (mottle) but does not significantly change displayed image brightness due to post-processing","Has no effect on digital images","Darkens the image significantly"],correctIndex:1,rationale:"In digital radiography, post-processing normalizes brightness regardless of mAs (within limits). However, higher mAs reduces quantum noise and improves signal-to-noise ratio. Lower mAs increases noise but reduces dose.",difficulty:5,category:"Image Production",topic:"digital exposure"},
    {id:"img-b3-005",stem:"The Norgaard method (ball-catcher position) of the hands is used to evaluate:",options:["Early rheumatoid arthritis changes in the metacarpophalangeal (MCP) joints","Scaphoid fractures","Colles fractures","Boxer's fractures"],correctIndex:0,rationale:"The ball-catcher (Norgaard) position demonstrates the radial aspects of the 2nd-5th MCP joints. It reveals early erosive changes of rheumatoid arthritis at the MCP joints before they become visible on standard PA projections.",difficulty:5,category:"Procedures",topic:"hand special views"},
    {id:"img-b3-006",stem:"In radiation protection, the concept of 'time' as a protective measure means:",options:["Time has no effect on radiation dose","Spending more time improves safety","Only applies to fluoroscopy","Minimizing the time spent in a radiation field reduces total exposure (dose = dose rate × time)"],correctIndex:3,rationale:"Total radiation dose is directly proportional to time of exposure: Dose = Dose Rate × Time. Halving the time halves the dose. This is why minimizing fluoroscopy time and using short exposure times are important ALARA practices.",difficulty:5,category:"Radiation Protection",topic:"cardinal principles"},
    {id:"img-b3-007",stem:"A scout (topogram/scanogram) image in CT is used for:",options:["Post-processing reconstruction","Final diagnosis","Planning the scan range, angle, and slice locations before the actual CT acquisition","Measuring radiation dose precisely"],correctIndex:2,rationale:"The CT scout is a low-dose projection image (similar to a radiograph) acquired before the diagnostic scan. It is used to prescribe scan range, slice orientation, and table positioning for the subsequent helical or axial scan.",difficulty:5,category:"Equipment Operation",topic:"CT scan planning"},
    {id:"img-b3-008",stem:"What is the effect on image quality when the x-ray tube focal spot size increases?",options:["Spatial resolution increases","Spatial resolution decreases (more geometric unsharpness/penumbra)","Contrast resolution improves","No effect on resolution"],correctIndex:1,rationale:"Larger focal spots produce more geometric unsharpness (penumbra) because the x-ray source is less point-like. The blur is proportional to focal spot size × OID/SOD. Small focal spots provide better resolution but have lower heat capacity.",difficulty:5,category:"Physics",topic:"focal spot effects"},
    {id:"img-b3-009",stem:"A patient presents for a portable chest x-ray and has an endotracheal (ET) tube. The radiograph should verify that:",options:["The ET tube tip is positioned 3-5 cm above the carina (T5-T6 level)","The ET tube is below the carina","The ET tube is in the esophagus","The ET tube tip is at the vocal cords"],correctIndex:0,rationale:"Proper ET tube position: tip 3-5 cm above the carina (approximately T5-T6 vertebral level). Too high risks extubation; too low causes right mainstem bronchus intubation. The position changes with head flexion/extension.",difficulty:5,category:"Procedures",topic:"tube position verification"},
    {id:"img-b3-010",stem:"Exposure latitude in digital radiography is:",options:["Non-existent in digital systems","Much wider than film-screen systems, allowing acceptable images over a broader range of exposures","The same as film-screen","Narrower than film-screen"],correctIndex:1,rationale:"Digital detectors have a much wider dynamic range (10,000:1 or greater) compared to film-screen (~30:1). This means digital systems can produce diagnostic images over a much broader range of exposures, though this can lead to exposure creep.",difficulty:5,category:"Image Production",topic:"dynamic range"},
    {id:"img-b3-011",stem:"The Judet views of the pelvis demonstrate:",options:["The hip joints only","The sacroiliac joints","The pubic symphysis","The anterior and posterior columns of the acetabulum for acetabular fracture evaluation"],correctIndex:3,rationale:"Judet views (internal and external oblique projections of the pelvis) evaluate the anterior and posterior acetabular columns and walls. They are essential for surgical planning of acetabular fractures.",difficulty:1,category:"Procedures",topic:"pelvic trauma"},
    {id:"img-b3-012",stem:"Grid cutoff appears as:",options:["A dark line across the center","Reduced density (increased brightness) on one or both sides of the image due to misalignment of the grid with the x-ray beam","Increased density on both sides","No visible effect"],correctIndex:1,rationale:"Grid cutoff occurs when the grid lines are not aligned with the diverging x-ray beam, causing the grid to absorb primary photons. Off-center, off-level, off-focus, and upside-down grid errors all produce characteristic cutoff patterns.",difficulty:1,category:"Equipment Operation",topic:"grid artifacts"},
    {id:"img-b3-013",stem:"What is the proper collimation for a PA chest radiograph?",options:["Only the heart","Only the right lung","Entire abdomen and chest","Collimate to include from the lung apices to the costophrenic angles, and from skin line to skin line laterally"],correctIndex:3,rationale:"PA chest collimation should include: superiorly above lung apices, inferiorly below costophrenic angles, and laterally to include both lateral lung margins. Tight collimation improves contrast and reduces dose.",difficulty:1,category:"Procedures",topic:"collimation standards"},
    {id:"img-b3-014",stem:"The half-value layer (HVL) of an x-ray beam represents:",options:["The exposure time","The patient dose","The thickness of a specified material that reduces beam intensity to 50% of its original value","The tube current"],correctIndex:2,rationale:"HVL measures beam quality (penetrating ability). It is the thickness of material (usually aluminum) that reduces beam intensity by half. Higher kVp = greater HVL = more penetrating beam. HVL is used for quality control testing.",difficulty:1,category:"Physics",topic:"beam quality"},
    {id:"img-b3-015",stem:"For a trauma patient with suspected cervical spine injury, the initial radiograph taken should be:",options:["Oblique C-spine with rotation","AP C-spine with the patient sitting up","Flexion/extension views","Cross-table lateral C-spine without moving the patient"],correctIndex:3,rationale:"A cross-table lateral C-spine is taken first because it can be obtained without moving the patient from the supine position or removing the cervical collar. All 7 cervical vertebrae and C7-T1 junction must be visualized.",difficulty:1,category:"Procedures",topic:"trauma imaging"},
    {id:"img-b3-016",stem:"Detective quantum efficiency (DQE) of a digital detector measures:",options:["The weight of the detector","The number of pixels","The physical size of the detector","How efficiently the detector converts x-ray photons into a useful image signal relative to the incident radiation"],correctIndex:3,rationale:"DQE is the most comprehensive measure of detector performance, representing the efficiency of signal conversion relative to incident radiation. Higher DQE means better image quality per unit dose. Flat panel detectors typically have higher DQE than CR.",difficulty:1,category:"Image Production",topic:"detector performance"},
    {id:"img-b3-017",stem:"The 10-day rule in radiation protection refers to:",options:["Scheduling elective abdominal/pelvic radiographic exams during the first 10 days of the menstrual cycle to minimize risk to a potential early pregnancy","Calibrating equipment every 10 days","Waiting 10 days after an exam to perform another","Processing films within 10 days"],correctIndex:0,rationale:"The 10-day rule limits elective pelvic/abdominal radiography of women of childbearing age to the first 10 days of the menstrual cycle (when pregnancy is unlikely). Most facilities now use pregnancy testing or patient declaration instead.",difficulty:1,category:"Radiation Protection",topic:"pregnancy protection"},
    {id:"img-b3-018",stem:"Streak artifacts in CT are commonly caused by:",options:["Room temperature","Patient weight","Table movement","Dense metallic objects (dental fillings, surgical hardware, contrast bolus) causing beam hardening and photon starvation"],correctIndex:3,rationale:"Streak artifacts result from beam hardening (preferential absorption of low-energy photons by dense objects) and photon starvation (insufficient photons reaching the detector behind dense objects). Metal artifact reduction algorithms can help.",difficulty:1,category:"Image Production",topic:"CT artifacts"},
    {id:"img-b3-019",stem:"What anatomical landmark corresponds to the level of T2-T3?",options:["The jugular notch (suprasternal notch)","The xiphoid process","The iliac crest","The symphysis pubis"],correctIndex:0,rationale:"The jugular notch (suprasternal notch) corresponds to approximately the T2-T3 vertebral level. Other landmarks: sternal angle = T4-T5, xiphoid = T9-T10, iliac crest = L4-L5, ASIS = S1-S2.",difficulty:1,category:"Procedures",topic:"anatomical landmarks"},
    {id:"img-b3-020",stem:"Which IV contrast injection technique is most commonly used for CT angiography (CTA)?",options:["Slow drip infusion","Power injector bolus injection at 3-5 mL/sec with bolus tracking or test bolus timing","Manual hand injection","Oral contrast"],correctIndex:1,rationale:"CTA requires rapid IV contrast delivery via power injector at 3-5 mL/sec to achieve high vascular contrast. Bolus tracking or test bolus determines optimal scan timing relative to contrast arrival in the vessels of interest.",difficulty:1,category:"Procedures",topic:"CT angiography"},
    {id:"img-b3-021",stem:"Aliasing artifact in ultrasound Doppler occurs when:",options:["The gel is insufficient","The Doppler frequency shift exceeds twice the pulse repetition frequency (Nyquist limit)","The transducer frequency is too low","The patient moves during the exam"],correctIndex:1,rationale:"Aliasing occurs when the Doppler shift exceeds the Nyquist limit (half the PRF). Flow appears to wrap around and display in the wrong direction. Solutions: increase PRF, decrease frequency, increase angle, or use CW Doppler.",difficulty:1,category:"Equipment Operation",topic:"Doppler ultrasound"},
    {id:"img-b3-022",stem:"The AP axial projection of the clavicle uses a cephalic tube angle of:",options:["45 degrees caudad","15-30 degrees cephalad to project the clavicle above the scapula and ribs","No angulation","60 degrees cephalad"],correctIndex:1,rationale:"The cephalic angulation (15-30°) projects the clavicle above the thorax and scapula, providing a clear view of the entire clavicle. The PA axial projection uses 15-30° caudad with the patient prone.",difficulty:1,category:"Procedures",topic:"clavicle radiography"},
    {id:"img-b3-023",stem:"In mammography, the average glandular dose for a standard two-view examination should not exceed:",options:["30 mGy","0.3 mGy","300 mGy","3 mGy (300 mrad) per view per the ACR accreditation standards"],correctIndex:3,rationale:"ACR mammography accreditation requires average glandular dose ≤3 mGy per view for a 4.2 cm compressed breast (50% glandular/50% adipose). Most modern systems achieve 1-2 mGy per view.",difficulty:1,category:"Radiation Protection",topic:"mammography dose"},
    {id:"img-b3-024",stem:"What is the primary advantage of computed radiography (CR) over conventional film-screen radiography?",options:["Better spatial resolution","Wider exposure latitude (dynamic range) and ability to digitally post-process images","Lower cost","Faster exposure time"],correctIndex:1,rationale:"CR's primary advantage is its wide dynamic range (approximately 10,000:1 vs film's ~30:1), allowing diagnostic images over a broader exposure range. Digital post-processing (windowing, edge enhancement) further optimizes image display.",difficulty:1,category:"Image Production",topic:"CR advantages"},
    {id:"img-b3-025",stem:"The AP projection of the ankle joint requires the CR to be directed to:",options:["The metatarsals","Midway between the malleoli at the level of the ankle joint","The knee joint","The calcaneus"],correctIndex:1,rationale:"For the AP ankle, the CR enters midway between the malleoli, perpendicular to the IR. The leg should be extended with the foot dorsiflexed. No rotation should be present (equal distance from malleoli to IR).",difficulty:1,category:"Procedures",topic:"ankle radiography"},
    {id:"img-b3-026",stem:"What type of interaction occurs when an x-ray photon passes through tissue without interacting?",options:["Compton scattering","Transmission (no interaction—the photon passes through unchanged)","Pair production","Photoelectric absorption"],correctIndex:1,rationale:"Transmitted photons pass through the patient without interaction and contribute to the image. The pattern of transmitted vs absorbed photons creates the radiographic image. Approximately 1-5% of photons are transmitted in radiography.",difficulty:2,category:"Physics",topic:"photon interactions"},
    {id:"img-b3-027",stem:"The lateral projection of the foot requires the CR to enter:",options:["At the ankle joint","At the toes","Perpendicular to the metatarsal-cuneiform area (midfoot)","At the calcaneus only"],correctIndex:2,rationale:"For a lateral foot, the CR enters at the base of the metatarsals/cuneiform area (midfoot). The patient is in lateral recumbent position with the affected side down, knee slightly flexed.",difficulty:2,category:"Procedures",topic:"foot radiography"},
    {id:"img-b3-028",stem:"Signal-to-noise ratio (SNR) in digital imaging is improved by:",options:["Increasing patient thickness","Using a smaller detector","Decreasing mAs","Increasing mAs (more photons = stronger signal relative to noise)"],correctIndex:3,rationale:"SNR improves with more photons reaching the detector (higher mAs, higher kVp, thinner patient). Better SNR means a cleaner image with less noise. However, increasing mAs also increases patient dose.",difficulty:2,category:"Image Production",topic:"image quality metrics"},
    {id:"img-b3-029",stem:"In CT, the term 'reconstruction kernel' or 'algorithm' refers to:",options:["The physical CT scanner shape","The patient positioning method","The mathematical filter used to reconstruct the image from raw data, affecting sharpness and noise characteristics","The contrast injection rate"],correctIndex:2,rationale:"Reconstruction kernels (filters) control the balance between spatial resolution and noise. Sharp/bone kernels enhance edges (high resolution, more noise). Smooth/soft tissue kernels reduce noise (less resolution).",difficulty:2,category:"Equipment Operation",topic:"CT reconstruction"},
    {id:"img-b3-030",stem:"The most appropriate imaging modality for evaluating a pregnant patient with suspected appendicitis is:",options:["CT with IV contrast","Nuclear medicine scan","Ultrasound as the initial study, followed by MRI if inconclusive","X-ray"],correctIndex:2,rationale:"Ultrasound is the first-line modality for suspected appendicitis in pregnancy (no ionizing radiation). If inconclusive, MRI (also no ionizing radiation) is recommended. CT is reserved as a last resort due to fetal radiation exposure.",difficulty:2,category:"Patient Care",topic:"pregnancy imaging"},
    {id:"img-b3-031",stem:"Which bone of the wrist is most commonly fractured?",options:["Lunate","Triquetrum","Scaphoid (navicular)","Pisiform"],correctIndex:2,rationale:"The scaphoid is the most commonly fractured carpal bone, often from a fall on an outstretched hand (FOOSH). It is vulnerable due to its blood supply pattern (retrograde). Initial radiographs may be negative; MRI or follow-up films are recommended.",difficulty:2,category:"Procedures",topic:"wrist injuries"},
    {id:"img-b3-032",stem:"A film badge (dosimeter) that has been exposed to excessive heat may show:",options:["Falsely low readings","Falsely elevated readings due to heat-induced fogging of the film","Perfectly accurate readings","No change"],correctIndex:1,rationale:"Film badges are sensitive to heat, humidity, and chemical exposure, which can fog the film and produce falsely high readings. OSL (optically stimulated luminescence) dosimeters are less affected by environmental conditions.",difficulty:2,category:"Radiation Protection",topic:"dosimetry artifacts"},
    {id:"img-b3-033",stem:"The central ray angle for the AP axial (Towne) projection of the knee to demonstrate the intercondylar fossa is:",options:["90 degrees","15 degrees cephalad","No angulation","40-45 degrees caudad with the knee extended, or 0 degrees with the knee flexed 40-45 degrees"],correctIndex:3,rationale:"The intercondylar fossa (tunnel view) can be obtained with 40-45° caudad angle (patient supine, knee extended) or PA axial with knee flexed. The Camp-Coventry method uses prone position with 40-50° caudad angulation.",difficulty:2,category:"Procedures",topic:"knee special views"},
    {id:"img-b3-034",stem:"In fluoroscopy, the image receptor closest to the patient provides:",options:["Worse image quality","More magnification","Reduced patient dose, less magnification, and better image quality compared to having the receptor farther away","Increased patient dose"],correctIndex:2,rationale:"Positioning the image receptor (II/flat panel) close to the patient reduces magnification, decreases the air gap (reducing scatter reaching the receptor), and results in less patient dose because the ABC doesn't need to increase output as much.",difficulty:2,category:"Radiation Protection",topic:"fluoroscopy optimization"},
    {id:"img-b3-035",stem:"Which of the following is NOT a component of the three cardinal principles of radiation protection?",options:["Time","Using high kVp techniques","Shielding","Distance"],correctIndex:1,rationale:"The three cardinal principles of radiation protection are Time (minimize), Distance (maximize), and Shielding (use barriers). Using high kVp is a technique factor that can reduce patient skin dose but is not one of the cardinal principles.",difficulty:2,category:"Radiation Protection",topic:"cardinal principles"},
    {id:"img-b3-036",stem:"A ring artifact in CT appears as:",options:["Bright streaks","Concentric circles centered on the isocenter, caused by a malfunctioning or miscalibrated detector element","Motion blur","Random noise pattern"],correctIndex:1,rationale:"Ring artifacts occur when a single detector element in a CT scanner malfunctions or becomes miscalibrated. During rotation, this bad detector traces a circle, creating visible ring patterns. Detector calibration corrects this.",difficulty:2,category:"Image Production",topic:"CT artifacts"},
    {id:"img-b3-037",stem:"The modified Cleaves method (bilateral frog-leg lateral) of the hips demonstrates:",options:["The lumbar spine","The sacroiliac joints","The acetabular columns","Both femoral heads, necks, and greater/lesser trochanters in a lateral perspective simultaneously"],correctIndex:3,rationale:"The modified Cleaves (frog-leg lateral, bilateral) positions both hips in flexion and abduction (40-45°). It demonstrates the femoral heads, necks, and relationship to the acetabulum bilaterally in one exposure.",difficulty:2,category:"Procedures",topic:"hip projections"},
    {id:"img-b3-038",stem:"Spatial resolution in digital imaging is typically measured in:",options:["Pixels per image","Megabytes","Hounsfield units","Line pairs per millimeter (lp/mm)"],correctIndex:3,rationale:"Spatial resolution is measured in line pairs per millimeter (lp/mm)—the ability to distinguish closely spaced objects. Typical digital radiography: 2.5-5 lp/mm. Film-screen: up to 10 lp/mm. Mammography: 15-20 lp/mm.",difficulty:2,category:"Image Production",topic:"resolution measurement"},
    {id:"img-b3-039",stem:"What is the purpose of applying compression to the breast during mammography?",options:["To cause discomfort","To reduce breast thickness, decrease scatter, improve contrast, reduce dose, and minimize motion","To distort anatomy","To increase exposure time"],correctIndex:1,rationale:"Breast compression: reduces thickness (less scatter, lower dose), spreads tissue (reduces overlap), equalizes tissue thickness, brings structures closer to IR (less geometric unsharpness), and minimizes motion.",difficulty:2,category:"Procedures",topic:"mammography technique"},
    {id:"img-b3-040",stem:"The Bergonié-Tribondeau Law states that cells are more radiosensitive if they are:",options:["Highly mitotic (rapidly dividing), undifferentiated, and have a long mitotic future","In the G0 phase of the cell cycle","Mature and non-dividing","Highly differentiated"],correctIndex:0,rationale:"Bergonié-Tribondeau (1906): radiosensitivity is directly proportional to mitotic rate and inversely proportional to degree of differentiation. Embryonic/fetal cells, blood-forming cells, and reproductive cells are most sensitive.",difficulty:2,category:"Radiation Protection",topic:"radiobiology"},
    {id:"img-b3-041",stem:"Dual-energy x-ray absorptiometry (DEXA/DXA) is the gold standard for measuring:",options:["Cardiac output","Liver function","Lung capacity","Bone mineral density for osteoporosis diagnosis"],correctIndex:3,rationale:"DXA uses two x-ray energies to differentiate bone from soft tissue and calculate bone mineral density (BMD). Results are reported as T-scores: -1 to -2.5 = osteopenia, below -2.5 = osteoporosis.",difficulty:3,category:"Equipment Operation",topic:"bone densitometry"},
    {id:"img-b3-042",stem:"When performing a cross-table lateral lumbar spine, the CR is directed:",options:["Horizontally (perpendicular to the IR) at the level of L3 (iliac crest)","At the symphysis pubis","Vertically through the abdomen","At 15 degrees cephalad"],correctIndex:0,rationale:"Cross-table lateral L-spine: patient supine, IR against the patient's side, horizontal beam directed at L3 (iliac crest level). Used when the patient cannot be turned on their side (trauma, post-operative).",difficulty:3,category:"Procedures",topic:"lateral spine technique"},
    {id:"img-b3-043",stem:"A patient scheduled for an MRI asks if there are any risks. The technologist should explain that MRI risks include:",options:["Radioactive contamination","Barium contrast reactions","Projectile effects from ferromagnetic objects, thermal effects from RF energy, and acoustic noise from gradient coils","X-ray radiation exposure"],correctIndex:2,rationale:"MRI safety concerns: ferromagnetic projectile risk, RF thermal effects (SAR - specific absorption rate), peripheral nerve stimulation from gradients, acoustic noise (up to 130 dB), and gadolinium contrast reactions. Thorough screening is essential.",difficulty:3,category:"Patient Care",topic:"MRI safety"},
    {id:"img-b3-044",stem:"Moiré artifact in digital radiography is caused by:",options:["Tube malfunction","Scatter radiation","Patient motion","Aliasing between the grid frequency and the detector sampling frequency when a stationary grid is used"],correctIndex:3,rationale:"Moiré pattern occurs when the spatial frequency of the stationary grid interacts with the detector element sampling frequency, creating banding patterns. Solutions: use a moving grid, remove the grid, or use grids designed for digital detectors.",difficulty:3,category:"Image Production",topic:"digital artifacts"},
    {id:"img-b3-045",stem:"The Grashey method of the shoulder demonstrates:",options:["The scapular Y view","The sternoclavicular joint","The acromioclavicular joint","The glenohumeral joint space in profile (patient rotated 35-45 degrees toward the affected side)"],correctIndex:3,rationale:"The Grashey (true AP shoulder) requires 35-45° posterior oblique rotation of the affected side toward the IR, placing the glenohumeral joint parallel to the IR. This opens the joint space for evaluation of arthritis, dislocation, or fracture.",difficulty:3,category:"Procedures",topic:"shoulder projections"},
    {id:"img-b3-046",stem:"The dose-length product (DLP) in CT scanning is calculated by multiplying CTDIvol by:",options:["The number of detector rows","The rotation time in seconds","The scan length in centimeters","The tube current in mA"],correctIndex:2,rationale:"DLP (mGy-cm) equals CTDIvol multiplied by the scan length. DLP provides a better estimate of total radiation exposure for a complete CT examination because it accounts for both the dose intensity and the volume of tissue irradiated.",difficulty:3,category:"Radiation Protection",topic:"CT dose metrics"},
    {id:"img-b3-047",stem:"What is the effect of reducing field of view (FOV) in CT reconstruction?",options:["Smaller FOV increases patient dose","Smaller FOV decreases resolution","Smaller FOV increases spatial resolution (smaller pixel size) but only for the reconstructed area","FOV has no effect on resolution"],correctIndex:2,rationale:"Pixel size = FOV / Matrix size. Reducing FOV with the same matrix makes each pixel smaller, improving spatial resolution. However, only the reconstructed area is displayed. FOV does not affect patient radiation dose.",difficulty:3,category:"Image Production",topic:"CT reconstruction"},
    {id:"img-b3-048",stem:"The optimal position for demonstrating the scaphoid bone without foreshortening is:",options:["PA with ulnar deviation (angle the wrist toward the ulnar side) and slight CR angulation toward the elbow","Lateral","PA with radial deviation","Oblique with fingers extended"],correctIndex:0,rationale:"PA with ulnar deviation elongates the scaphoid by reducing its normal palmar tilt. The modified Stecher method adds 20° cephalad angulation or elevates the wrist 20°. These positions demonstrate the full length of the scaphoid.",difficulty:3,category:"Procedures",topic:"wrist special views"},
    {id:"img-b3-049",stem:"What is the relationship between kVp and contrast in conventional (film-screen) radiography?",options:["kVp has no effect on contrast","Higher kVp produces lower contrast (longer scale of contrast); lower kVp produces higher contrast (shorter scale)","Higher kVp increases contrast","Lower kVp decreases contrast"],correctIndex:1,rationale:"Higher kVp: more Compton scatter (reducing contrast), more penetration through all tissues (less differential absorption). Lower kVp: more photoelectric absorption (greater contrast between different tissues). Digital systems can adjust contrast in post-processing.",difficulty:3,category:"Image Production",topic:"contrast factors"},
    {id:"img-b3-050",stem:"During an IVU (intravenous urogram), the kidneys are best visualized at which time after contrast injection?",options:["Immediately (0 seconds)","Nephrogram phase: 1-3 minutes (renal parenchyma); Pyelogram phase: 5-15 minutes (collecting system filling)","After 1 hour","After 24 hours"],correctIndex:1,rationale:"IVU timing: immediate scout, arterial nephrogram (1 min), parenchymal nephrogram (2-3 min), pyelogram/collecting system (5-15 min), bladder filling (15-20 min), post-void. Delayed images for obstruction evaluation.",difficulty:3,category:"Procedures",topic:"urography"},
    {id:"img-b3-051",stem:"Which of the following patient conditions would contraindicate the use of iodinated IV contrast?",options:["A common cold","Hypertension","Mild headache","Severe renal insufficiency (eGFR <30) increases the risk of contrast-induced nephropathy"],correctIndex:3,rationale:"Severe renal insufficiency (eGFR <30 mL/min) significantly increases risk of contrast-induced nephropathy (CIN). Other contraindications include severe allergic reaction history and active thyrotoxicosis. Hydration and reduced-volume protocols may be used.",difficulty:3,category:"Patient Care",topic:"contrast contraindications"},
    {id:"img-b3-052",stem:"Iterative reconstruction in CT compared to filtered back projection (FBP):",options:["Produces identical images","Increases noise","Takes less processing time","Reduces image noise, allowing lower dose scans to maintain image quality"],correctIndex:3,rationale:"Iterative reconstruction algorithms use mathematical modeling to reduce noise while maintaining resolution. This allows 20-40% dose reduction compared to FBP at equivalent image quality. Most modern CT scanners use iterative reconstruction.",difficulty:3,category:"Equipment Operation",topic:"CT reconstruction methods"},
    {id:"img-b3-053",stem:"For an AP projection of the thoracic spine, the CR should enter at:",options:["T1","T7 (approximately at the level of the inferior angle of the scapulae)","L3","T12"],correctIndex:1,rationale:"The CR for AP thoracic spine enters at T7, approximately at the level of the inferior angle of the scapulae. This centers the thoracic spine (T1-T12) on the image. An anode heel effect technique positions the cathode toward the thicker lower thorax.",difficulty:3,category:"Procedures",topic:"thoracic spine"},
    {id:"img-b3-054",stem:"X-ray tube heat units (HU) are calculated as:",options:["kVp × mAs only","mA × time only","kVp × mA × exposure time × generator factor (1.0 for single-phase, 1.35 for 3-phase/6-pulse, 1.41 for 3-phase/12-pulse or HF)","kVp squared"],correctIndex:2,rationale:"Heat units consider all factors affecting heat production: HU = kVp × mAs × generator factor. Three-phase and high-frequency generators are more efficient (higher factor), producing more HU per exposure.",difficulty:3,category:"Physics",topic:"tube heating"},
    {id:"img-b3-055",stem:"Standard precautions in the radiology department include:",options:["Only washing hands before eating","Hand hygiene, use of PPE for all patients, proper handling of sharps, and equipment disinfection between patients","Only wearing gloves for bloody procedures","No precautions needed for radiology"],correctIndex:1,rationale:"Standard precautions treat all patients as potentially infectious. They include hand hygiene, gloves, gowns, masks/eye protection when splash risk exists, proper sharps disposal, and equipment cleaning between patients.",difficulty:3,category:"Patient Care",topic:"infection control"},
    {id:"img-b3-056",stem:"In MRI, a T2-weighted image makes fluid appear:",options:["Dark","Invisible","Bright (hyperintense) because fluid has a long T2 relaxation time","Identical to bone"],correctIndex:2,rationale:"T2-weighted images use long TE and long TR. Fluid (long T2) maintains signal longer and appears bright. Fat also appears relatively bright on T2. T2 is excellent for detecting edema, inflammation, and other fluid-containing pathology.",difficulty:3,category:"Equipment Operation",topic:"MRI contrast weighting"},
    {id:"img-b3-057",stem:"Proper centering for a lateral projection of the elbow is:",options:["The epicondyles are superimposed, with the CR directed to the midpoint of the elbow joint","With the arm fully pronated","At the wrist joint","With the arm in AP position"],correctIndex:0,rationale:"For a true lateral elbow, the epicondyles must be superimposed (perpendicular to IR). The elbow is flexed 90°, with the CR entering the lateral epicondyle. The olecranon process should be seen in profile.",difficulty:3,category:"Procedures",topic:"elbow radiography"},
    {id:"img-b3-058",stem:"Annual radiation dose limit for a fetal exposure (gestational dose) is:",options:["No limit","500 mSv","5 mSv (0.5 rem) total gestational dose, with 0.5 mSv per month recommended","50 mSv"],correctIndex:2,rationale:"NCRP recommends a maximum gestational dose of 5 mSv (500 mrem) with monthly monitoring to keep the monthly dose below 0.5 mSv. A pregnant worker should declare pregnancy to initiate additional monitoring and protection.",difficulty:3,category:"Radiation Protection",topic:"pregnancy dose limits"},
    {id:"img-b3-059",stem:"The Trendelenburg position places the patient:",options:["Lateral recumbent","Supine with the head lower than the feet (table tilted 15-20° head down)","Supine with the head higher than the feet","Prone with the head elevated"],correctIndex:1,rationale:"Trendelenburg position: head-down tilt. Used during air-contrast barium enema to fill the transverse colon, for shock treatment (to improve venous return), and during some interventional procedures.",difficulty:3,category:"Patient Care",topic:"patient positioning"},
    {id:"img-b3-060",stem:"What is the typical effective dose from a standard chest PA/lateral examination?",options:["100 mSv","Approximately 0.1 mSv (10 mrem)","0.001 mSv","10 mSv"],correctIndex:1,rationale:"A standard 2-view chest x-ray delivers approximately 0.1 mSv effective dose (equivalent to about 10 days of natural background radiation). This is one of the lowest-dose diagnostic imaging procedures.",difficulty:3,category:"Radiation Protection",topic:"typical exam doses"},
    {id:"img-b3-061",stem:"Beam hardening artifact in CT occurs because:",options:["The gantry tilts incorrectly","The patient moves","Lower-energy photons are preferentially absorbed as the beam passes through dense tissue, shifting the beam to higher average energy","The beam becomes softer"],correctIndex:2,rationale:"As the polychromatic x-ray beam passes through tissue, lower-energy photons are preferentially absorbed (beam hardening). This causes cupping artifacts (edges brighter than center) and dark bands between dense structures.",difficulty:3,category:"Physics",topic:"CT artifacts"},
    {id:"img-b3-062",stem:"Which type of contrast medium is considered safest for evaluating a potential bowel perforation?",options:["No contrast needed","Barium paste","Water-soluble iodinated contrast (e.g., Gastrografin)—never barium, which causes peritonitis if it leaks","Barium sulfate suspension"],correctIndex:2,rationale:"If bowel perforation is suspected, water-soluble contrast (Gastrografin or Omnipaque) must be used. Barium leaking into the peritoneal cavity causes severe chemical peritonitis and adhesions. Water-soluble contrast is absorbed and excreted.",difficulty:3,category:"Patient Care",topic:"contrast selection"},
    {id:"img-b3-063",stem:"The Swimmer's lateral (Twining method) is performed when:",options:["Flexion/extension views are needed","The AP projection is inadequate","Standard lateral C-spine fails to demonstrate C7-T1 due to shoulder superimposition","The patient cannot open their mouth"],correctIndex:2,rationale:"The Swimmer's lateral positions one arm raised overhead (shoulder elevated) and the other down (shoulder depressed) to separate the shoulders and visualize the C7-T1 cervicothoracic junction that may be obscured by shoulder overlap.",difficulty:3,category:"Procedures",topic:"cervicothoracic junction"},
    {id:"img-b3-064",stem:"What does the deviation index (DI) in digital radiography indicate?",options:["The grid ratio used","The patient's body mass index","The distance from the tube to the IR","How much the actual exposure deviates from the target exposure index—a DI of 0 indicates ideal exposure"],correctIndex:3,rationale:"DI = 10 × log₁₀(EI/EIT). DI of 0 = target exposure. Positive DI = overexposure. Negative DI = underexposure. AAPM recommends keeping DI within ±1.0 for optimal image quality.",difficulty:3,category:"Image Production",topic:"exposure optimization"},
    {id:"img-b3-065",stem:"What is the minimum kVp recommended for chest radiography in adults to penetrate the mediastinum?",options:["40-50 kVp","80-90 kVp","60-70 kVp","110-125 kVp (high kVp technique)"],correctIndex:3,rationale:"High kVp technique (110-125) for chest radiography ensures adequate penetration of the mediastinum and heart while maintaining long-scale contrast to visualize both lung markings and mediastinal structures.",difficulty:3,category:"Image Production",topic:"chest technique"},
    {id:"img-b3-066",stem:"The four phases of decontamination for a radiology room after treating a patient with a communicable disease are:",options:["Only wiping the table","Closing the room permanently","Just spraying disinfectant","Cleaning, disinfection, verification, and documentation"],correctIndex:3,rationale:"Room decontamination involves: 1) Cleaning (removing visible soil), 2) Disinfection (applying appropriate disinfectant per pathogen), 3) Verification (ensuring all surfaces were treated), 4) Documentation (recording decontamination).",difficulty:3,category:"Patient Care",topic:"infection control"},
    {id:"img-b3-067",stem:"In a PA projection of the wrist, the CR should be directed to:",options:["The midcarpal area (midpoint of the wrist)","The metacarpophalangeal joints","The distal radioulnar joint","The elbow joint"],correctIndex:0,rationale:"For the PA wrist, the CR enters at the midcarpal area, midway between the distal radius/ulna and the metacarpal bases. The hand is pronated flat on the IR with fingers slightly flexed.",difficulty:3,category:"Procedures",topic:"wrist radiography"},
    {id:"img-b3-068",stem:"Which of these materials has the highest atomic number and provides the best radiation shielding?",options:["Aluminum (Al, Z=13)","Steel (Fe, Z=26)","Lead (Pb, Z=82)","Copper (Cu, Z=29)"],correctIndex:2,rationale:"Lead (Z=82) has the highest atomic number among common shielding materials and is the most efficient at absorbing diagnostic x-ray photons through photoelectric absorption. Standard lead equivalency for aprons is 0.25-0.5 mm Pb.",difficulty:3,category:"Radiation Protection",topic:"shielding materials"},
    {id:"img-b3-069",stem:"Arthrography involves the injection of contrast medium into:",options:["A blood vessel","A joint space to evaluate internal joint structures (menisci, ligaments, cartilage)","The urinary bladder","The spinal canal"],correctIndex:1,rationale:"Arthrography injects contrast (iodinated or gadolinium for MR arthrography) into a joint space (shoulder, knee, hip, wrist) to distend the joint and visualize internal structures. MR arthrography is currently the gold standard.",difficulty:3,category:"Procedures",topic:"arthrography"},
    {id:"img-b3-070",stem:"The modulation transfer function (MTF) is used to measure:",options:["Patient dose","The ability of an imaging system to reproduce different spatial frequencies (spatial resolution performance)","Contrast-to-noise ratio","Image noise only"],correctIndex:1,rationale:"MTF quantifies how faithfully an imaging system reproduces objects of different sizes (spatial frequencies). An MTF of 1.0 = perfect reproduction. As spatial frequency increases, MTF decreases. Higher MTF at a given frequency = better resolution.",difficulty:3,category:"Image Production",topic:"system performance"},
    {id:"img-b3-071",stem:"A patient presenting with chest pain and shortness of breath is most likely to need which emergency imaging study?",options:["Hand x-ray","Chest x-ray (PA and lateral if possible) as the initial study","Skull x-ray","Knee x-ray"],correctIndex:1,rationale:"Chest x-ray is the initial imaging study for acute chest pain and dyspnea. It can identify pneumothorax, pleural effusion, cardiomegaly, pulmonary edema, pneumonia, rib fractures, and widened mediastinum.",difficulty:3,category:"Procedures",topic:"emergency imaging"},
    {id:"img-b3-072",stem:"Tube current modulation in CT automatically adjusts:",options:["The kVp only","The mA based on patient size and attenuation to maintain consistent image quality while reducing dose","The table speed","The slice thickness"],correctIndex:1,rationale:"Automatic tube current modulation (ATCM) varies mA based on patient anatomy (angular and longitudinal modulation). It reduces dose by lowering mA for thinner regions (shoulders, neck) and increasing mA for thicker regions (pelvis).",difficulty:3,category:"Radiation Protection",topic:"CT dose reduction"},
    {id:"img-b3-073",stem:"The maximum permissible dose for a member of the general public (non-occupational) per year is:",options:["1 mSv (0.1 rem) per year","50 mSv","500 mSv","5 mSv"],correctIndex:0,rationale:"NCRP recommends a maximum annual effective dose of 1 mSv (100 mrem) for members of the general public. This applies to individuals who are not occupationally exposed, including visitors to radiology departments.",difficulty:3,category:"Radiation Protection",topic:"public dose limits"},
    {id:"img-b3-074",stem:"What is the purpose of a radiolucent sponge in radiographic positioning?",options:["To increase patient dose","To support and maintain patient positioning without creating visible artifacts on the image","To hold the image receptor","To absorb radiation"],correctIndex:1,rationale:"Radiolucent sponges (made of foam or similar material) support body parts in the desired position without showing on the radiograph. They are essential for consistent, comfortable positioning.",difficulty:3,category:"Equipment Operation",topic:"positioning aids"},
    {id:"img-b3-075",stem:"The Law of Reciprocity states that:",options:["Any combination of mA and time that produces the same mAs will produce the same exposure to the image receptor","Higher kVp always requires more mAs","Reciprocity only applies to film systems","Time cannot be changed without changing mA"],correctIndex:0,rationale:"Reciprocity: 100 mA × 0.1 s = 10 mAs produces the same exposure as 200 mA × 0.05 s = 10 mAs. This allows adjustment of mA and time independently while maintaining consistent exposure. Film reciprocity fails at extreme values.",difficulty:3,category:"Physics",topic:"exposure relationships"},
    {id:"img-b3-076",stem:"Which projection best demonstrates the intercondylar eminence of the knee?",options:["Lateral projection","AP projection with the CR directed perpendicular to the knee","Tangential (sunrise) view","Tunnel (intercondylar notch) view"],correctIndex:1,rationale:"The intercondylar eminence (tibial spines) is best demonstrated on the AP knee projection where the CR is perpendicular to the joint space. The tunnel view shows the intercondylar notch of the femur.",difficulty:3,category:"Procedures",topic:"knee anatomy"},
    {id:"img-b3-077",stem:"What is the purpose of the compensation filter in radiography?",options:["To reduce image receptor sensitivity","To change beam energy","To increase patient dose","To equalize exposure across body parts of uneven thickness (e.g., wedge filter for AP foot, trough filter for AP thoracic spine)"],correctIndex:3,rationale:"Compensation filters (wedge, trough, bowtie) attenuate the beam more in areas corresponding to thinner anatomy, producing more uniform exposure across the image. This is particularly useful for the foot, thoracic spine, and chest.",difficulty:3,category:"Equipment Operation",topic:"compensation filters"},
    {id:"img-b3-078",stem:"A patient who has been NPO (nothing by mouth) for an extended period may develop:",options:["Hypertension","Improved contrast visualization only","Hyperhydration","Dehydration and hypoglycemia, which should be monitored especially in elderly and diabetic patients"],correctIndex:3,rationale:"Extended NPO status can cause dehydration and hypoglycemia, particularly dangerous for elderly patients, diabetics, and children. Technologists should monitor patients for dizziness, weakness, confusion, and diaphoresis.",difficulty:3,category:"Patient Care",topic:"NPO monitoring"},
    {id:"img-b3-079",stem:"What is the minimum number of projections required to evaluate a long bone for fracture?",options:["Two projections at 90 degrees to each other (typically AP and lateral)","Three projections","Four projections","One projection"],correctIndex:0,rationale:"A minimum of two projections at 90° to each other is required to evaluate a fracture. A fracture visible on one projection may be occult on the other. Both joints above and below the injury should be included.",difficulty:3,category:"Procedures",topic:"fracture evaluation"},
    {id:"img-b3-080",stem:"Effective dose (measured in Sievert) accounts for:",options:["Only the x-ray beam energy","Only the exposure","Both the type of radiation and the radiosensitivity of the tissues/organs exposed","Only the absorbed dose"],correctIndex:2,rationale:"Effective dose = Σ(absorbed dose × radiation weighting factor × tissue weighting factor). It accounts for: type of radiation (WR, all 1.0 for x-rays) and relative radiosensitivity of exposed tissues (WT). Used for comparing different procedures.",difficulty:3,category:"Radiation Protection",topic:"effective dose"},
    {id:"img-b3-081",stem:"Proper hand hygiene technique with soap and water should last at least:",options:["2 seconds","1 minute","5 seconds","20 seconds of vigorous washing"],correctIndex:3,rationale:"CDC recommends at least 20 seconds of hand washing with soap and water, including all surfaces of hands, between fingers, and under nails. Alcohol-based hand rub should be used for at least 15 seconds if hands are not visibly soiled.",difficulty:4,category:"Patient Care",topic:"hand hygiene"},
    {id:"img-b3-082",stem:"In CT, what does 'helical' or 'spiral' scanning mean?",options:["Scanning occurs only at specific intervals","The tube remains stationary","The patient rotates","The patient table moves continuously through the gantry while the x-ray tube rotates, creating a helical path of data acquisition"],correctIndex:3,rationale:"In helical/spiral CT, continuous table movement during tube rotation creates a volumetric dataset. This allows faster scanning, reduced motion artifacts, and multiplanar/3D reconstructions. The pitch determines the tightness of the helix.",difficulty:4,category:"Equipment Operation",topic:"CT scanning modes"},
    {id:"img-b3-083",stem:"The open-mouth (Fuchs) method is used to demonstrate:",options:["The odontoid process (dens) of C2 through the open mouth","The mandible","The occipital bone","The C7-T1 junction"],correctIndex:0,rationale:"The open-mouth odontoid view demonstrates the dens (odontoid process) of C2, the lateral masses of C1 (atlas), and the C1-C2 articulation through the open mouth. Essential for evaluating C1-C2 injuries.",difficulty:4,category:"Procedures",topic:"cervical spine views"},
    {id:"img-b3-084",stem:"A step-wedge (penetrometer) image is used in quality control to assess:",options:["Room temperature","X-ray beam reproducibility, exposure consistency, and display calibration","Staff competency","Patient positioning accuracy"],correctIndex:1,rationale:"The step wedge (aluminum step phantom) produces a graduated density pattern. Comparing images over time verifies exposure consistency, kVp accuracy, processing consistency, and digital detector calibration.",difficulty:4,category:"Equipment Operation",topic:"QC testing"},
    {id:"img-b3-085",stem:"When an image appears too dark (overexposed) on a film-screen system, the most likely cause is:",options:["Insufficient mAs","Use of slow-speed screens","Underdevelopment","Excessive mAs or kVp for the body part thickness"],correctIndex:3,rationale:"Overexposure (too dark film) results from excessive mAs and/or kVp for the body part. In digital radiography, overexposure increases the exposure index but post-processing may maintain acceptable brightness—check the EI.",difficulty:4,category:"Image Production",topic:"exposure errors"},
    {id:"img-b3-086",stem:"For CT of the abdomen with oral contrast, the patient typically drinks the contrast:",options:["60-90 minutes before the exam to allow bowel opacification","24 hours before","Immediately before scanning","After the exam"],correctIndex:0,rationale:"Oral contrast (dilute barium or iodinated solution) is given 60-90 minutes before abdominal CT to opacify the bowel lumen. Additional contrast may be given immediately before scanning to fill the stomach.",difficulty:4,category:"Procedures",topic:"CT contrast preparation"},
    {id:"img-b3-087",stem:"The umbra and penumbra of an x-ray beam relate to:",options:["Sharp shadow (true image) and blurred edge (geometric unsharpness) of an object's radiographic image","Patient positioning terms","Radiation dose measurements","Types of contrast agents"],correctIndex:0,rationale:"Umbra is the sharp central shadow of an object (true image). Penumbra is the blurred transition zone at the edges caused by the finite focal spot size. Smaller focal spot, shorter OID, and longer SID reduce penumbra.",difficulty:4,category:"Physics",topic:"geometric unsharpness"},
    {id:"img-b3-088",stem:"A patient with diabetes who is taking metformin and needs a CT scan with IV iodinated contrast should:",options:["Stop metformin permanently","Have metformin held for 48 hours after contrast administration and have renal function checked before resuming","Continue metformin without any changes","Take extra metformin before the scan"],correctIndex:1,rationale:"Metformin is held for 48 hours after iodinated contrast due to risk of contrast-induced nephropathy reducing renal function, potentially causing metformin accumulation and lactic acidosis. Renal function (eGFR) must be normal before restarting.",difficulty:4,category:"Patient Care",topic:"metformin contrast protocol"},
    {id:"img-b3-089",stem:"When performing a lateral projection of the skull, the interpupillary line should be:",options:["Not relevant to positioning","Parallel to the IR","At 45 degrees to the IR","Perpendicular to the image receptor (ensuring the skull is in a true lateral position)"],correctIndex:3,rationale:"A true lateral skull requires the interpupillary line to be perpendicular to the IR (midsagittal plane parallel to IR). The infraorbitomeatal line should be parallel to the transverse axis of the IR.",difficulty:4,category:"Procedures",topic:"skull positioning"},
    {id:"img-b3-090",stem:"What are the three forms of secondary radiation barriers in diagnostic radiology?",options:["Primary beam, scatter, and remnant radiation","kVp, mAs, and SID","Time, distance, and shielding","Scatter radiation, leakage radiation, and secondary radiation from walls/objects"],correctIndex:3,rationale:"Secondary barriers protect against: 1) Scatter radiation from the patient, 2) Leakage radiation through the tube housing, 3) Secondary scatter from walls/objects. Primary barriers protect against the useful (primary) beam.",difficulty:4,category:"Radiation Protection",topic:"structural shielding"},
    {id:"img-b3-091",stem:"The sunrise (tangential/Merchant) view of the patella is performed to evaluate:",options:["The hip joint","The knee joint only","The tibial plateau","The patellofemoral joint, patellar alignment, and patellar articular surface"],correctIndex:3,rationale:"The tangential (sunrise/skyline/Merchant) view demonstrates the patella in profile against the femoral condyles, evaluating patellofemoral alignment, patellar tilt, subluxation, and articular surface.",difficulty:4,category:"Procedures",topic:"patellar projections"},
    {id:"img-b3-092",stem:"What is the dose equivalent limit for the hands/extremities of an occupationally exposed worker per year?",options:["500 mSv (50 rem)","150 mSv","50 mSv","5 mSv"],correctIndex:0,rationale:"NCRP dose limits for extremities (hands, forearms, feet, ankles) are 500 mSv/year. This is higher than the whole-body limit (50 mSv) because extremities have lower radiosensitivity. Ring dosimeters monitor hand dose.",difficulty:4,category:"Radiation Protection",topic:"extremity dose limits"},
    {id:"img-b3-093",stem:"Which body habitus is the most common, accounting for approximately 50% of the population?",options:["Hypersthenic","Asthenic","Hyposthenic","Sthenic"],correctIndex:3,rationale:"Sthenic habitus (approximately 50% of population): moderate build. Hyposthenic (35%): slightly thinner. Hypersthenic (5%): massive build, organs positioned higher and more transverse. Asthenic (10%): very thin, organs low and vertical.",difficulty:4,category:"Patient Care",topic:"body habitus"},
    {id:"img-b3-094",stem:"What size focal spot should be used for magnification radiography?",options:["Any focal spot size","Large focal spot (1.0-2.0 mm)","Small (fractional) focal spot, typically 0.1-0.3 mm","Focal spot size is irrelevant"],correctIndex:2,rationale:"Magnification radiography requires a small (fractional) focal spot to maintain spatial resolution at increased magnification. A large focal spot would create excessive penumbra (geometric unsharpness) at the magnified OID.",difficulty:4,category:"Image Production",topic:"focal spot selection"},
    {id:"img-b3-095",stem:"During IV contrast injection, extravasation occurs when:",options:["Contrast leaks out of the vein into surrounding soft tissue, causing local swelling, pain, and potential tissue damage","Contrast is administered too slowly","The wrong contrast is used","Contrast enters the arterial system"],correctIndex:0,rationale:"Extravasation: contrast leaks into subcutaneous tissue. Symptoms: pain, swelling, redness at the injection site. Treatment: stop injection, elevate limb, cold/warm compresses, monitor. Severe cases: compartment syndrome (rare).",difficulty:4,category:"Patient Care",topic:"contrast complications"},
    {id:"img-b3-096",stem:"What effect does patient body habitus have on the required radiographic technique?",options:["Thinner patients need more mAs","Body size has no effect on technique","Larger patients always need lower kVp","Larger/thicker patients require increased mAs and/or kVp to adequately penetrate the anatomy"],correctIndex:3,rationale:"Body habitus directly affects x-ray attenuation. Larger/thicker patients absorb more radiation, requiring higher mAs and/or kVp. Technique charts should include adjustments for different patient sizes (pediatric through hypersthenic).",difficulty:4,category:"Image Production",topic:"technique adjustment"},
    {id:"img-b3-097",stem:"The Y-view (scapular lateral) of the shoulder demonstrates:",options:["The sternoclavicular joint","The clavicle","The acromioclavicular joint","The scapular body in profile with the humeral head superimposed on the glenoid fossa—useful for evaluating shoulder dislocation direction"],correctIndex:3,rationale:"The scapular Y view demonstrates the coracoid process (anterior), acromion (superior), and scapular body (posterior) forming a 'Y.' The humeral head should sit at the junction. Anterior or posterior displacement indicates dislocation direction.",difficulty:4,category:"Procedures",topic:"shoulder dislocation evaluation"},
    {id:"img-b3-098",stem:"The signal intensity of fat on a T1-weighted MRI image is:",options:["Invisible","Dark (hypointense)","Bright (hyperintense) because fat has a short T1 relaxation time","The same as water"],correctIndex:2,rationale:"Fat has a short T1 relaxation time, meaning it recovers longitudinal magnetization quickly, producing high signal (bright) on T1-weighted images. This is why T1 images show good anatomical detail with bright fat contrast.",difficulty:4,category:"Equipment Operation",topic:"MRI tissue signal"},
    {id:"img-b3-099",stem:"For a PA projection of the chest, the patient's hands should be placed:",options:["Clasped behind the back","On the hips with palms out (or arms wrapped around the chest board) to rotate the scapulae laterally, clearing the lung fields","Raised above the head","At the sides"],correctIndex:1,rationale:"Placing hands on hips with palms outward rotates the scapulae laterally, moving them out of the lung fields. Alternative: arms wrapped around the chest board. This clears the scapulae from the lung fields.",difficulty:4,category:"Procedures",topic:"chest positioning"},
    {id:"img-b3-100",stem:"What is the purpose of post-processing edge enhancement in digital radiography?",options:["To reduce patient dose","To improve the visibility of borders between structures by amplifying spatial frequency differences","To increase noise","To darken the entire image"],correctIndex:1,rationale:"Edge enhancement (unsharp mask filtering) amplifies high-frequency signals at tissue boundaries, making edges more visible. Excessive enhancement can create halo artifacts and amplify noise.",difficulty:4,category:"Image Production",topic:"post-processing"}
  ];
  